var e=[{id:`L3_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`하아…… 멀다.`,JPN:`はぁ……遠いな。`,ENG:`*Sigh...* It's so far away.`,TWN:`呼……好遠喔。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`그래도 며칠 새 꽤 많이 걸었어.`,JPN:`でも数日でかなり歩いたね。`,ENG:`But I've closed the distance quite a lot in the last few days.`,TWN:`這幾天走了好多路，`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`표지판이 맞다면 오늘 하루 부지런히 걸어가면 도착할 수 있을 거야.`,JPN:`標識が正しければ、今日一日頑張って歩いたら到着できそう。`,ENG:`If the signs are correct, then I should be there by the end of the day today.`,TWN:`路標沒寫錯的話，應該今天再加點油就會到了。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CORRUPTED_NPC_LUCID_PET`,text:{KOREA:`크릉.`,JPN:`ガルン。`,ENG:`Grr.`,TWN:`呼嚕。`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`이제 다리가 보이기 시작했어.`,JPN:`やっと橋が見えてきた。`,ENG:`Finally, I can see the bridge.`,TWN:`好像看到橋了。`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`그런데……`,JPN:`ところで……`,ENG:`But...`,TWN:`不過……`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`어째서 앞에 검문소 같은 게 있는 거지? 군인들인 걸까?`,JPN:`どうして橋の前に検問所みたいなものがあるんだろう？
政府軍の人たちかな？`,ENG:`Is that a checkpoint in front of it? Are those people soldiers?`,TWN:`前面那個是檢查哨吧？是軍人設的嗎？`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`군인이라면 도움을 받을 수 있을지도 모르지만…….`,JPN:`政府軍なら助けてもらえるかもしれない……`,ENG:`If they are, perhaps they can help me...`,TWN:`是軍人的話，他們說不定會幫我……`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`……아앗, 숨어!`,JPN:`……あっ、隠れて！`,ENG:`... Ah, duck!`,TWN:`……啊！快躲起來！`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CORRUPTED_NPC_LUCID_PET`,text:{KOREA:`킁!`,JPN:`ガルン！`,ENG:`Grr!`,TWN:`呼嚕！`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…….`,TWN:`……`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`차가 지나갔어.`,JPN:`車が行ったみたい。`,ENG:`A car passed by.`,TWN:`剛剛開過去的那台車上，`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`어린아이들도 타고 있는 것 같았는데…….`,JPN:`幼い子どもたちが乗っていた気がする……`,ENG:`I think there were children in it...`,TWN:`似乎載著許多小孩……`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CORRUPTED_NPC_LUCID_PET`,text:{KOREA:`크르륵!`,JPN:`ガルルッ！`,ENG:`Grrrrr!`,TWN:`呼嚕嚕！`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`총소리! 검문소 방향이야!`,JPN:`銃声！　検問所の方よ！`,ENG:`Gunshots! From the checkpoint!`,TWN:`有槍聲！是檢查哨的方向！`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`SOLDIER_NPC_NULL_NULL`,text:{KOREA:`엎드려! 엎드리라고!`,JPN:`伏せろ！　伏せろと言ったんだ！`,ENG:`Get down! Get down!`,TWN:`趴下！我叫你趴下！`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`SOLDIER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`OLDMAN_VOICE_NULL_NULL`,text:{KOREA:`왜, 왜들 이러십니까. 저흰 그냥 여길 통과하려고 했을 뿐인데요.`,JPN:`ど、どうしたのですか。ワシらはここを通ろうとしただけです。`,ENG:`Wh-why are you doing this? We're only trying to cross the bridge.`,TWN:`你們這是在做什麼？我們不過是要通過這裡而已。`},stage:{bg:`COUNTRYROAD_02`,slots:{L:null,C:{char_id:`SOLDIER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};